import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobServices from './features/landing/JobServices';
import Testimonials from './features/landing/Testimonials';
import CTA from './features/landing/CTA';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';
import Register from './components/auth/Register';

const ViewAllButton = () => {
    const navigate = useNavigate();
    return (
        <div style={{ textAlign: 'center', marginTop: '20px' }}>
            <button onClick={() => navigate('/eksplorasi')} style={{ padding: '10px 24px', background: 'transparent', border: '1px solid #ea580c', color: '#ea580c', borderRadius: '8px', cursor: 'pointer' }}>
                Lihat Semua
            </button>
        </div>
    );
};

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('home');
    const navigate = useNavigate();

    const handleNavigation = (menu) => {
        setActiveMenu(menu);
        if (menu === 'eksplorasi') navigate('/eksplorasi');
        if (menu === 'home') navigate('/');
    };

    return (
        <div style={{ background: '#080402', minHeight: '100vh', color: '#fff' }}>
            <Navbar isAuthenticated={isAuthenticated} activeMenu={activeMenu} setActiveMenu={handleNavigation} />
            <main>
                <Routes>
                    <Route path="/" element={
                        <>
                            <Hero />
                            <HowItWorks />
                            <JobServices />
                            <section style={{ maxWidth: '900px', margin: '40px auto', padding: '0 20px' }}>
                                <h2 style={{ fontSize: '20px', marginBottom: '20px', color: '#fef3c7' }}>Lowongan Terbaru</h2>
                                <JobListContainer limit={3} />
                                <ViewAllButton />
                            </section>
                            <Testimonials />
                            <CTA />
                        </>
                    } />
                </Routes>
            </main>
            <Footer />
        </div>
    );
};

const AppWrapper = () => <Router><App /></Router>;
export default AppWrapper;
